solution_code:
#include <iostream>

int main()
{
    int a, b;
    std::cin >> a >> b;

    if (b == 0)
    {
        std::cout << "Error: division by zero\n";
    }
    else
    {
        std::cout << "Result: " << a / b << '\n';
    }

    return 0;
}

