solution_code:
#include <iostream>
#include <cassert>

int percentage(int part, int total)
{
    assert(total > 0);
    return part * 100 / total;
}

int main()
{
    int part, total;
    std::cin >> part >> total;
    std::cout << "Percentage: " << percentage(part, total) << '\n';
    return 0;
}
